```class Solution {
public:
    bool makeStringsEqual(string s, string target) {
        int cnt[2] = {0, 0}, cntT[2] = {0, 0};
        for (int i = 0; i < s.size(); i++) {
            cnt[s[i] - '0']++;
            cntT[target[i] - '0']++;
        }
        return cnt[1] >= cntT[1];
    }
};
